import sys

pairs = {")": "(", "]": "["}

def balanced(line):
    stack = []
    for ch in line:
        if ch in "([":
            stack.append(ch)
        elif ch in ")]":
            if not stack or stack.pop() != pairs[ch]:
                return False
    return not stack

out = []
for line in sys.stdin.read().splitlines():
    if line == ".":
        break
    out.append("yes" if balanced(line) else "no")
print("\n".join(out))

